    if region_match:
        code = region_match.group(1).upper()
        city_part = cleaned[:region_match.start()].strip()
        city_keys = _city_keys_from_text(city_part, country_key=None)
        city_hint = city_part.casefold()
        if code == "IN" and (
            city_keys
